def f(expr):
    s = expr.replace(' ', '')
    n = len(s)
    i = 0

    def parse_expression():
        nonlocal i
        value = parse_term()
        while i < n and s[i] in '+-':
            op = s[i]
            i += 1
            rhs = parse_term()
            if op == '+':
                value += rhs
            else:
                value -= rhs
        return value

    def parse_term():
        nonlocal i
        value = parse_factor()
        while i < n and s[i] == '*':
            i += 1
            rhs = parse_factor()
            value *= rhs
        return value

    def parse_factor():
        nonlocal i
        if s[i] == '(':
            i += 1
            val = parse_expression()
            i += 1  # skip ')'
            return val
        start = i
        while i < n and s[i].isdigit():
            i += 1
        return int(s[start:i])

    return parse_expression()
